let input=document.getElementById("userInput"),output=document.getElementById("output"),charCount=document.createElement("p");function getRandomColor(){return`hsl(${Math.floor(360*Math.random())}, 100%, 50%)`}charCount.id="charCount",charCount.style.fontSize="14px",charCount.style.color="gray",charCount.textContent="Characters: 0",output.parentNode.appendChild(charCount),input.addEventListener("input",function(){var t=this.value||"👀";output.textContent=t,output.style.color=getRandomColor(),output.style.transition="color 0.3s ease-in-out",charCount.textContent="Characters: "+t.length}),input.addEventListener("dblclick",function(){this.value="",output.textContent="👀",charCount.textContent="Characters: 0"});